import React, { useState, useEffect, useMemo } from 'react';
import axios from 'axios';

function App() {
  const [walletBalance, setWalletBalance] = useState(10000); 
  const [holdings, setHoldings] = useState([]); 
  const [marketPrices, setMarketPrices] = useState({}); 
  const [token] = useState("ВСТАВЬ_СВОЙ_JWT_ТОКЕН");

  useEffect(() => {

    const ws = new WebSocket('ws://localhost:5000', token);

    ws.onmessage = (event) => {
      const data = JSON.parse(event.data);
   
      if (data.type === "TICKER_UPDATE") {
        setMarketPrices(prev => ({
          ...prev,
          [data.payload.ticker]: data.payload.price
        }));
      }
    };

    return () => ws.close();
  }, [token]);

  const totalNetWorth = useMemo(() => {
    const assetsValue = holdings.reduce((sum, item) => {
      const currentPrice = marketPrices[item.ticker] || 0;
      return sum + (item.amount * currentPrice);
    }, 0);
    return walletBalance + assetsValue;
  }, [walletBalance, holdings, marketPrices]);

  const handleBuy = async (ticker, amount) => {
    try {
      const res = await axios.post('http://localhost:5000/api/buy', 
        { ticker, amount },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setWalletBalance(res.data.balance);
      setHoldings(res.data.holdings);
    } catch (err) {
      alert("Ошибка: проверьте баланс или сервер");
    }
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'sans-serif' }}>
      <h1>Торговая платформа PEX</h1>
      <div style={{ border: '2px solid #333', padding: '15px', borderRadius: '10px' }}>
        <h3>Ваш баланс: ${walletBalance.toLocaleString()}</h3>
        <h2 style={{ color: 'green' }}>
          Общий капитал (Net Worth): ${totalNetWorth.toLocaleString()}
        </h2>
      </div>

      <div style={{ marginTop: '20px' }}>
        <h3>Ваш портфель:</h3>
        {holdings.length === 0 ? <p>У вас пока нет акций</p> : (
          <ul>
            {holdings.map(h => (
              <li key={h.ticker}>
                {h.ticker}: {h.amount} шт. (Тек. цена: ${marketPrices[h.ticker] || '???'})
              </li>
            ))}
          </ul>
        )}
      </div>

      <button onClick={() => handleBuy('DEV', 1)} style={{ padding: '10px', marginTop: '10px' }}>
        Купить 1 акцию $DEV
      </button>
    </div>
  );
}

export default App;
